INSERT INTO `parties` (`id`, `numero`, `name`, `description`, `thematique_id`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 1, 'Le petit voyage de Koulou la tortue', 'Lorsqu\'on voyage on tient compte du temps et de l\'espace, c\'est-à-dire de l\'heure de départ ou d\'arrivée, de la durée du voyage... notre ami la tortue n\'a pas l\'air de le savoir !', 1, '2025-10-04 18:46:46', '2025-10-04 18:46:46', NULL),
(2, 2, 'La petite tête de mule de Fari l\'âne', 'La têtutesse qualifie une personne qui refuse d\'obéir à une règle/loi pour ne que chercher à obtenir de manière déterminer sa propre liberté. C\'est le cas de notre ami la Fari.', 1, '2025-10-04 18:46:46', '2025-10-04 18:46:46', NULL),
(3, 1, 'Le grand retard de Koulou chez le roi lion', 'Pendant cette séance, il s’agit d’amener les enfants d’abord à comprendre ce qu’est le retard par rapport à la ponctualité. En outre, il s’agit de les amener à faire une démarcation conceptuelle entre ces deux concepts. Le plus simple pour eux serait certainement de faire cette distinction conceptuelle entre être en retard et être ponctuel.', 2, '2025-10-04 19:03:48', '2025-10-04 19:03:48', NULL),
(4, 1, 'Le recyclage', 'Le recyclage', 7, '2025-10-14 09:19:51', '2025-10-14 09:19:51', NULL);
